6758 /// it into the appropriate icmp lt or icmp gt instruction. This transform
6759 /// allows them to be folded in visitICmpInst.
6760 static ICmpInst *canonicalizeCmpWithConstant(ICmpInst &I) {
6761   ICmpInst::Predicate Pred = I.getPredicate();
6762   if (ICmpInst::isEquality(Pred) || !ICmpInst::isIntPredicate(Pred) ||
6763       InstCombiner::isCanonicalPredicate(Pred))
6764     return nullptr;
