2454 Instruction *InstCombinerImpl::foldICmpShrConstant(ICmpInst &Cmp,
2455                                                    BinaryOperator *Shr,
2456                                                    const APInt &C) {
2457   // An exact shr only shifts out zero bits, so:
2458   // icmp eq/ne (shr X, Y), 0 --> icmp eq/ne X, 0
2459   Value *X = Shr->getOperand(0);
2460   CmpInst::Predicate Pred = Cmp.getPredicate();
2461   if (Cmp.isEquality() && Shr->isExact() && C.isZero())
2462     return new ICmpInst(Pred, X, Cmp.getOperand(1));
2463 
2464   bool IsAShr = Shr->getOpcode() == Instruction::AShr;
2465   const APInt *ShiftValC;
2466   if (match(X, m_APInt(ShiftValC))) {
2467     if (Cmp.isEquality())
2468       return foldICmpShrConstConst(Cmp, Shr->getOperand(1), C, *ShiftValC);
2469 
2470     // (ShiftValC >> Y) >s -1 --> Y != 0 with ShiftValC < 0
2471     // (ShiftValC >> Y) <s  0 --> Y == 0 with ShiftValC < 0
2472     bool TrueIfSigned;
2473     if (!IsAShr && ShiftValC->isNegative() &&
2474         isSignBitCheck(Pred, C, TrueIfSigned))
2475       return new ICmpInst(TrueIfSigned ? CmpInst::ICMP_EQ : CmpInst::ICMP_NE,
2476                           Shr->getOperand(1),
2477                           ConstantInt::getNullValue(X->getType()));
2478 
2479     // If the shifted constant is a power-of-2, test the shift amount directly:
2480     // (ShiftValC >> Y) >u C --> X <u (LZ(C) - LZ(ShiftValC))
2481     // (ShiftValC >> Y) <u C --> X >=u (LZ(C-1) - LZ(ShiftValC))
2482     if (!IsAShr && ShiftValC->isPowerOf2() &&
2483         (Pred == CmpInst::ICMP_UGT || Pred == CmpInst::ICMP_ULT)) {
2484       bool IsUGT = Pred == CmpInst::ICMP_UGT;
2485       assert(ShiftValC->uge(C) && "Expected simplify of compare");
2486       assert((IsUGT || !C.isZero()) && "Expected X u< 0 to simplify");
2487 
2488       unsigned CmpLZ = IsUGT ? C.countl_zero() : (C - 1).countl_zero();
2489       unsigned ShiftLZ = ShiftValC->countl_zero();
2490       Constant *NewC = ConstantInt::get(Shr->getType(), CmpLZ - ShiftLZ);
2491       auto NewPred = IsUGT ? CmpInst::ICMP_ULT : CmpInst::ICMP_UGE;
2492       return new ICmpInst(NewPred, Shr->getOperand(1), NewC);
2493     }
2494   }
2495 
2496   const APInt *ShiftAmtC;
2497   if (!match(Shr->getOperand(1), m_APInt(ShiftAmtC)))
2498     return nullptr;
2499 
2500   // Check that the shift amount is in range. If not, don't perform undefined
2501   // shifts. When the shift is visited it will be simplified.
2502   unsigned TypeBits = C.getBitWidth();
2503   unsigned ShAmtVal = ShiftAmtC->getLimitedValue(TypeBits);
2504   if (ShAmtVal >= TypeBits || ShAmtVal == 0)
2505     return nullptr;
2506 
2507   bool IsExact = Shr->isExact();
2508   Type *ShrTy = Shr->getType();
2509   // TODO: If we could guarantee that InstSimplify would handle all of the
2510   // constant-value-based preconditions in the folds below, then we could assert
2511   // those conditions rather than checking them. This is difficult because of
2512   // undef/poison (PR34838).
2513   if (IsAShr && Shr->hasOneUse()) {
2514     if (IsExact && (Pred == CmpInst::ICMP_SLT || Pred == CmpInst::ICMP_ULT) &&
2515         (C - 1).isPowerOf2() && C.countLeadingZeros() > ShAmtVal) {
2516       // When C - 1 is a power of two and the transform can be legally
2517       // performed, prefer this form so the produced constant is close to a
2518       // power of two.
2519       // icmp slt/ult (ashr exact X, ShAmtC), C
2520       // --> icmp slt/ult X, (C - 1) << ShAmtC) + 1
2521       APInt ShiftedC = (C - 1).shl(ShAmtVal) + 1;
2522       return new ICmpInst(Pred, X, ConstantInt::get(ShrTy, ShiftedC));
2523     }
