6780 /// If we have a comparison with a non-canonical predicate, if we can update
6781 /// all the users, invert the predicate and adjust all the users.
6782 CmpInst *InstCombinerImpl::canonicalizeICmpPredicate(CmpInst &I) {
6783   // Is the predicate already canonical?
6784   CmpInst::Predicate Pred = I.getPredicate();
6785   if (InstCombiner::isCanonicalPredicate(Pred))
6786     return nullptr;
6787 
6788   // Can all users be adjusted to predicate inversion?
6789   if (!InstCombiner::canFreelyInvertAllUsersOf(&I, /*IgnoredUser=*/nullptr))
6790     return nullptr;
6791 
6792   // Ok, we can canonicalize comparison!
6793   // Let's first invert the comparison's predicate.
6794   I.setPredicate(CmpInst::getInversePredicate(Pred));
6795   I.setName(I.getName() + ".not");
6796 
6797   // And, adapt users.
6798   freelyInvertAllUsersOf(&I);
6799 
6800   return &I;
